protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
        // Preserve the old name so existing documents and direct SQL queries still work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id format from "Product|123" to "123".
        // Preserve the old format so existing documents remain accessible.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // Removed HasIndex — EF Core 9 Cosmos provider now throws on HasIndex.
    // Manage indexing via the container's indexing policy in Azure Portal / Bicep.
}

